{% set _seo_pages = [
  {"path": "",              "freq": "weekly",  "pri": "0.9"},
  {"path": "/intermediate", "freq": "monthly", "pri": "0.8"},
  {"path": "/expert",       "freq": "monthly", "pri": "0.8"},
  {"path": "/how-to-play",  "freq": "monthly", "pri": "0.7"},
  {"path": "/strategy",     "freq": "monthly", "pri": "0.7"},
  {"path": "/about",        "freq": "monthly", "pri": "0.5"},
] %}
{% for _lang in sitemap_langs %}
